        exception_mapping = {
            (ProtocolError, OSError, ClosedPoolError): ConnectionError,
            _ProxyError: ProxyError,
            _SSLError: SSLError,
            ReadTimeoutError: ReadTimeout,
            _InvalidHeader: InvalidHeader,
